import Database from 'better-sqlite3';
import { fileURLToPath } from 'url';
import path from 'path';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const dbPath = path.join(__dirname, '..', 'data', 'wildlife.db');
const db = new Database(dbPath);

try { db.exec("ALTER TABLE locations ADD COLUMN type TEXT DEFAULT 'dive'"); } catch {}

db.exec(`
  DELETE FROM sightings;
  DELETE FROM locations;
  DELETE FROM species;
`);

const insertSpecies = db.prepare(`
  INSERT INTO species (common_name, scientific_name, category, conservation_status, description)
  VALUES (@common_name, @scientific_name, @category, @conservation_status, @description)
`);

