// A handful of parks (e.g. Etosha, Hwange) were accidentally defined twice in
// parkData with slightly different descriptions/coordinates. Keep only the last
// definition for each name — insertion order below relies on locationIds[name]
// pointing at a single row, so an earlier duplicate would otherwise be inserted
// as an orphan location with zero sightings.
const dedupedParkData = Object.values(
  parkData.reduce((acc, p) => {
    acc[p.name] = p;
    return acc;
  }, {})
);

for (const p of dedupedParkData) {
  const info = insertParkLocation.run({ ...p, type: 'park' });
  locationIds[p.name] = info.lastInsertRowid;
}

const insertSighting = db.prepare(`
  INSERT INTO sightings (location_id, species_id, start_month, end_month, likelihood, notes)
  VALUES (@location_id, @species_id, @start_month, @end_month, @likelihood, @notes)
`);

