// A few (location, species) pairs were accidentally authored twice across
// separate content blocks (same sighting, differently-worded notes) — keep
// only the first so each species appears once per location's sighting list.
const seenSightingKeys = new Set();
const dedupedSightingData = sightingData.filter((s) => {
  const key = `${s.location}␀${s.species}`;
  if (seenSightingKeys.has(key)) return false;
  seenSightingKeys.add(key);
  return true;
});

for (const s of dedupedSightingData) {
  insertSighting.run({
    location_id: locationIds[s.location],
    species_id: speciesIds[s.species],
    start_month: s.start_month,
    end_month: s.end_month,
    likelihood: s.likelihood,
    notes: s.notes,
  });
}

console.log('Seeded:', speciesData.length, 'species,', locationData.length + dedupedParkData.length, 'locations (' + locationData.length + ' dive +', dedupedParkData.length + ' parks),', dedupedSightingData.length, 'sightings');
db.close();
